@dataclass
class RoutingDecision:
    model: str
    tier: str
    reason: str


def multi_tier_route(query: str, router: EmbeddingRouter) -> RoutingDecision:
    # Tier 1: cheapest safe signal — token count
    tokens = len(enc.encode(query))
    if tokens > 500:
        return RoutingDecision("gpt-4o", "tier-1", "long query")

    # Tier 2: rule-based keyword check (no API call)
    if any(kw in query.lower() for kw in COMPLEX_KEYWORDS):
        return RoutingDecision("gpt-4o", "tier-1", "complex keyword")

    # Tier 3: embedding classifier (one cheap embedding call)
    model = router.route(query)
    return RoutingDecision(model, "tier-2", "embedding classifier")


def production_chat(user_message: str) -> str:
    decision = multi_tier_route(user_message, router)
    print(f"[{decision.tier}] {decision.reason} → {decision.model}")

    response = client.chat.completions.create(
        model=decision.model,
        messages=[{"role": "user", "content": user_message}],
    )
    return response.choices[0].message.content

