from openai import OpenAI
from dataclasses import dataclass, field

client = OpenAI()


@dataclass
class RoutingEvalResult:
    total: int = 0
    correctly_routed_simple: int = 0
    correctly_routed_complex: int = 0
    misrouted_complex_to_simple: int = 0  # quality-damaging
    misrouted_simple_to_complex: int = 0  # cost-wasting
    cost_saved_usd: float = 0.0
    quality_penalty: float = 0.0

    @property
    def misrouting_rate(self) -> float:
        return (self.misrouted_complex_to_simple + self.misrouted_simple_to_complex) / max(self.total, 1)

    @property
    def harmful_misrouting_rate(self) -> float:
        return self.misrouted_complex_to_simple / max(self.total, 1)


def evaluate_router(
    labelled_test_set: list[dict],  # {"query": str, "ground_truth": "simple"|"complex"}
    router_fn,  # callable: str -> "simple"|"complex"
    gpt4o_cost_per_1m: float = 2.50,
    mini_cost_per_1m: float = 0.15,
    avg_tokens: int = 500,
) -> RoutingEvalResult:
    result = RoutingEvalResult(total=len(labelled_test_set))
    cost_per_token_diff = (gpt4o_cost_per_1m - mini_cost_per_1m) / 1_000_000

    for item in labelled_test_set:
        query = item["query"]
        gt = item["ground_truth"]
        predicted = router_fn(query)

        is_correct = (predicted == gt)
        if gt == "simple" and predicted == "simple":
            result.correctly_routed_simple += 1
            result.cost_saved_usd += avg_tokens * cost_per_token_diff
        elif gt == "complex" and predicted == "complex":
            result.correctly_routed_complex += 1
        elif gt == "complex" and predicted == "simple":
            result.misrouted_complex_to_simple += 1  # quality loss
        else:
            result.misrouted_simple_to_complex += 1  # wasted cost

    return result


def print_eval_report(result: RoutingEvalResult) -> None:
    print(f"Total queries evaluated:     {result.total}")
    print(f"Correctly routed simple:     {result.correctly_routed_simple}")
    print(f"Correctly routed complex:    {result.correctly_routed_complex}")
    print(f"Misrouted (complex→simple):  {result.misrouted_complex_to_simple}  ← quality impact")
    print(f"Misrouted (simple→complex):  {result.misrouted_simple_to_complex}  ← cost waste")
    print(f"Harmful misrouting rate:     {result.harmful_misrouting_rate:.2%}")
    print(f"Total misrouting rate:       {result.misrouting_rate:.2%}")
    print(f"Estimated cost saved:        ${result.cost_saved_usd:.2f}")
